import React from 'react';
import { Link } from 'react-router-dom';
import {
  X, DollarSign, Lightbulb, AlertTriangle, ExternalLink, BarChart3,
} from 'lucide-react';
import { SeverityBadge } from './FindingBadges';
import { formatCurrency } from '../utils/format';
import { toDisplayText } from '../utils/formatDisplay';
import AssetIcon from './AssetIcon';

export default function ResourceInsightDrawer({
  resource,
  findings = [],
  onClose,
  title,
  iconKey,
}) {
  if (!resource) return null;

  const rid = resource.id || resource.resource_id || '';
  const name = resource.name || resource.resource_name || 'Resource';
  const monthlyCost = resource.monthlyCostUsd ?? resource.monthly_cost_usd ?? 0;
  const dbFindings = resource.analysisSummary || [];
  const displayFindings = findings.length > 0
    ? findings
    : dbFindings.map((item, index) => ({
      id: `db-summary-${index}`,
      rule_name: item.rule_name,
      severity: item.severity,
      detail: item.recommendation,
      recommendation: item.recommendation,
      estimated_savings_usd: item.estimated_savings_usd,
    }));
  const totalSavings = displayFindings.reduce((s, f) => s + (f.estimated_savings_usd || 0), 0);
  const critical = displayFindings.filter((f) => f.severity === 'CRITICAL').length;
  const high = displayFindings.filter((f) => f.severity === 'HIGH').length;

  return (
    <div className="insight-drawer-overlay" onClick={onClose} role="presentation">
      <aside
        className="insight-drawer"
        onClick={(e) => e.stopPropagation()}
        role="dialog"
        aria-modal="true"
        aria-labelledby="insight-drawer-title"
      >
        <header className="insight-drawer__header">
          <div className="insight-drawer__title-row">
            <AssetIcon iconKey={iconKey} size={22} />
            <div>
              <h2 id="insight-drawer-title" className="insight-drawer__title">{title || name}</h2>
              <p className="insight-drawer__sub">{name}</p>
            </div>
          </div>
          <button type="button" className="btn btn-ghost btn-icon-only" onClick={onClose} aria-label="Close">
            <X size={18} />
          </button>
        </header>

        <div className="insight-drawer__metrics">
          <div className="insight-metric">
            <span className="insight-metric__label"><DollarSign size={12} /> MTD cost (CAD)</span>
            <span className="insight-metric__value">
              {monthlyCost > 0 ? formatCurrency(monthlyCost, { currency: 'CAD' }) : '—'}
            </span>
          </div>
          <div className="insight-metric">
            <span className="insight-metric__label"><BarChart3 size={12} /> Open findings</span>
            <span className="insight-metric__value">{displayFindings.length}</span>
          </div>
          <div className="insight-metric insight-metric--success">
            <span className="insight-metric__label"><DollarSign size={12} /> Est. savings</span>
            <span className="insight-metric__value">
              {totalSavings > 0 ? formatCurrency(totalSavings, { currency: 'CAD' }) : '—'}
            </span>
          </div>
        </div>

        <dl className="insight-drawer__meta">
          {resource.location && (
            <>
              <dt>Location</dt>
              <dd>{resource.location}</dd>
            </>
          )}
          {(resource.resourceGroup || resource.resource_group) && (
            <>
              <dt>Resource group</dt>
              <dd>{resource.resourceGroup || resource.resource_group}</dd>
            </>
          )}
          {resource.state && toDisplayText(resource.state) !== '—' && (
            <>
              <dt>State</dt>
              <dd>{toDisplayText(resource.state)}</dd>
            </>
          )}
          {resource.sku && toDisplayText(resource.sku) !== '—' && (
            <>
              <dt>SKU</dt>
              <dd>{toDisplayText(resource.sku)}</dd>
            </>
          )}
        </dl>

        {rid && (
          <p className="insight-drawer__arm-id" title={rid}>{rid}</p>
        )}

        {resource._pools?.length > 0 && (
          <section className="insight-drawer__section">
            <h3 className="insight-drawer__section-title">Node pools</h3>
            <div className="table-wrap">
              <table>
                <thead><tr><th>Pool</th><th>Mode</th><th>Count</th><th>VM size</th></tr></thead>
                <tbody>
                  {resource._pools.map((pp) => (
                    <tr key={pp.name}>
                      <td>{pp.name}</td>
                      <td>{pp.mode || '—'}</td>
                      <td>{pp.count ?? 0}</td>
                      <td style={{ fontFamily: 'monospace', fontSize: '0.78rem' }}>{pp.vmSize || '—'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </section>
        )}

        <section className="insight-drawer__section">
          <h3 className="insight-drawer__section-title">
            <AlertTriangle size={14} />
            Optimization analysis
            {(critical > 0 || high > 0) && (
              <span className="insight-drawer__badges">
                {critical > 0 && <span className="badge badge-critical">{critical} critical</span>}
                {high > 0 && <span className="badge badge-high">{high} high</span>}
              </span>
            )}
          </h3>

          {displayFindings.length === 0 ? (
            <p className="insight-drawer__empty">
              No open findings for this resource. Run analysis from the Dashboard to generate recommendations.
            </p>
          ) : (
            <ul className="insight-finding-list">
              {displayFindings.map((f) => (
                <li key={f.id} className="insight-finding-card">
                  <div className="insight-finding-card__head">
                    <SeverityBadge severity={f.severity} />
                    <span className="insight-finding-card__rule">{f.rule_name}</span>
                    {f.estimated_savings_usd > 0 && (
                      <span className="insight-finding-card__savings">
                        {formatCurrency(f.estimated_savings_usd, { currency: 'CAD' })}/mo
                      </span>
                    )}
                  </div>
                  <p className="insight-finding-card__detail">{toDisplayText(f.detail)}</p>
                  <p className="insight-finding-card__rec">
                    <Lightbulb size={12} />
                    {toDisplayText(f.recommendation)}
                  </p>
                  {f.waste_score != null && (
                    <div className="insight-finding-card__score">
                      Waste score: <strong>{f.waste_score}</strong>/100
                      {f.confidence_score != null && (
                        <> · Confidence: <strong>{f.confidence_score}%</strong></>
                      )}
                    </div>
                  )}
                </li>
              ))}
            </ul>
          )}
        </section>

        <footer className="insight-drawer__footer">
          <Link to="/findings" className="btn btn-secondary" onClick={onClose}>
            <ExternalLink size={13} /> View all findings
          </Link>
        </footer>
      </aside>
    </div>
  );
}
